<template>
<div :style='{"border":"2px solid #DF847F","width":"90%","padding":"20px 0","margin":"10px auto","position":"relative","background":"#fff"}'>
    <el-form
	  :style='{"width":"100%","position":"relative"}'
      class="add-update-preview"
      ref="ruleForm"
      :model="ruleForm"
      :rules="rules"
      label-width="80px"
    >
          <el-form-item :style='{"padding":"10px","margin":"0 0 10px","background":"#fff"}' label="线路名称" prop="xianlumingcheng">
            <el-input v-model="ruleForm.xianlumingcheng" 
                placeholder="线路名称" clearable :disabled=" false  ||ro.xianlumingcheng"></el-input>
          </el-form-item>
          <el-form-item :style='{"padding":"10px","margin":"0 0 10px","background":"#fff"}' label="线路图片" v-if="type!='cross' || (type=='cross' && !ro.xianlutupian)" prop="xianlutupian">
            <file-upload
            tip="点击上传线路图片"
            action="file/upload"
            :limit="3"
            :multiple="true"
            :fileUrls="ruleForm.xianlutupian?ruleForm.xianlutupian:''"
            @change="xianlutupianUploadChange"
            ></file-upload>
          </el-form-item>
            <el-form-item :style='{"padding":"10px","margin":"0 0 10px","background":"#fff"}' class="upload" v-else label="线路图片" prop="xianlutupian">
                <img v-if="ruleForm.xianlutupian.substring(0,4)=='http'" class="upload-img" style="margin-right:20px;" v-bind:key="index" :src="ruleForm.xianlutupian.split(',')[0]" width="100" height="100">
                <img v-else class="upload-img" style="margin-right:20px;" v-bind:key="index" v-for="(item,index) in ruleForm.xianlutupian.split(',')" :src="baseUrl+item" width="100" height="100">
            </el-form-item>
          <el-form-item :style='{"padding":"10px","margin":"0 0 10px","background":"#fff"}' label="景点名称" prop="jingdianmingcheng">
            <el-select  @change="jingdianmingchengChange" v-model="ruleForm.jingdianmingcheng" placeholder="请选择景点名称">
              <el-option
                  v-for="(item,index) in jingdianmingchengOptions"
                  :key="index"
                  :label="item"
                  :value="item">
              </el-option>
            </el-select>
          </el-form-item>
          <el-form-item :style='{"padding":"10px","margin":"0 0 10px","background":"#fff"}' label="景点类型" prop="jingdianleixing">
            <el-input v-model="ruleForm.jingdianleixing" 
                placeholder="景点类型" clearable :disabled=" false  ||ro.jingdianleixing"></el-input>
          </el-form-item>
          <el-form-item :style='{"padding":"10px","margin":"0 0 10px","background":"#fff"}' label="景点位置" prop="jingdianweizhi">
            <el-input v-model="ruleForm.jingdianweizhi" 
                placeholder="景点位置" clearable :disabled=" false  ||ro.jingdianweizhi"></el-input>
          </el-form-item>
          <el-form-item :style='{"padding":"10px","margin":"0 0 10px","background":"#fff"}' label="起点" prop="qidian">
            <el-input v-model="ruleForm.qidian" 
                placeholder="起点" clearable :disabled=" false  ||ro.qidian"></el-input>
          </el-form-item>
          <el-form-item :style='{"padding":"10px","margin":"0 0 10px","background":"#fff"}' label="途径路段" prop="tujingluduan">
            <el-input v-model="ruleForm.tujingluduan" 
                placeholder="途径路段" clearable :disabled=" false  ||ro.tujingluduan"></el-input>
          </el-form-item>
          <el-form-item :style='{"padding":"10px","margin":"0 0 10px","background":"#fff"}' label="终点" prop="zhongdian">
            <el-input v-model="ruleForm.zhongdian" 
                placeholder="终点" clearable :disabled=" false  ||ro.zhongdian"></el-input>
          </el-form-item>
          <el-form-item :style='{"padding":"10px","margin":"0 0 10px","background":"#fff"}' label="线路费用" prop="xianlufeiyong">
			<el-input-number v-model="ruleForm.xianlufeiyong" placeholder="线路费用" :readonly="ro.xianlufeiyong"></el-input-number>
          </el-form-item>
          <el-form-item :style='{"padding":"10px","margin":"0 0 10px","background":"#fff"}' label="报团名额" prop="baotuanminge">
            <el-input v-model.number="ruleForm.baotuanminge" 
                placeholder="报团名额" clearable :disabled=" false  ||ro.baotuanminge"></el-input>
          </el-form-item>
          <el-form-item :style='{"padding":"10px","margin":"0 0 10px","background":"#fff"}' label="出发日期" prop="chufariqi">
              <el-date-picker
				  :disabled=" false  ||ro.chufariqi"
                  value-format="yyyy-MM-dd HH:mm:ss"
                  v-model="ruleForm.chufariqi" 
                  type="datetime"
                  :picker-options="chufariqiPickerOptions"
                  placeholder="出发日期">
              </el-date-picker>
          </el-form-item>
          <el-form-item :style='{"padding":"10px","margin":"0 0 10px","background":"#fff"}' label="交通方式" prop="jiaotongfangshi">
            <el-input v-model="ruleForm.jiaotongfangshi" 
                placeholder="交通方式" clearable :disabled=" false  ||ro.jiaotongfangshi"></el-input>
          </el-form-item>
          <el-form-item :style='{"padding":"10px","margin":"0 0 10px","background":"#fff"}' label="导游工号" prop="daoyougonghao">
            <el-input v-model="ruleForm.daoyougonghao" 
                placeholder="导游工号" clearable :disabled=" false  ||ro.daoyougonghao"></el-input>
          </el-form-item>
          <el-form-item :style='{"padding":"10px","margin":"0 0 10px","background":"#fff"}' label="导游姓名" prop="daoyouxingming">
            <el-input v-model="ruleForm.daoyouxingming" 
                placeholder="导游姓名" clearable :disabled=" false  ||ro.daoyouxingming"></el-input>
          </el-form-item>
          <el-form-item :style='{"padding":"10px","margin":"0 0 10px","background":"#fff"}' label="联系方式" prop="lianxifangshi">
            <el-input v-model="ruleForm.lianxifangshi" 
                placeholder="联系方式" clearable :disabled=" false  ||ro.lianxifangshi"></el-input>
          </el-form-item>
          <el-form-item :style='{"padding":"10px","margin":"0 0 10px","background":"#fff"}' label="线路详情" prop="xianluxiangqing">
            <editor 
                :style='{"padding":"0","boxShadow":"none","margin":"0","borderColor":"#ccc","backgroundColor":"#fff","borderRadius":"0","borderWidth":"0","width":"100%","borderStyle":"solid","height":"auto"}'
                v-model="ruleForm.xianluxiangqing" 
                class="editor" 
                action="file/upload">
            </editor>
          </el-form-item>
          <el-form-item :style='{"padding":"10px","margin":"0 0 10px","background":"#fff"}' label="导游介绍" prop="gerenlvli">
            <editor 
                :style='{"padding":"0","boxShadow":"none","margin":"0","borderColor":"#ccc","backgroundColor":"#fff","borderRadius":"0","borderWidth":"0","width":"100%","borderStyle":"solid","height":"auto"}'
                v-model="ruleForm.gerenlvli" 
                class="editor" 
                action="file/upload">
            </editor>
          </el-form-item>

      <el-form-item :style='{"padding":"0","margin":"0"}'>
        <el-button :style='{"border":"0","cursor":"pointer","padding":"0 10px","margin":"0 20px 0 0","outline":"none","color":"rgba(255, 255, 255, 1)","borderRadius":"4px","background":"#DF847F","width":"auto","lineHeight":"30px","fontSize":"14px","height":"30px"}'  type="primary" @click="onSubmit">提交</el-button>
        <el-button :style='{"border":"0","cursor":"pointer","padding":"0 10px","margin":"0","outline":"none","color":"#fff","borderRadius":"4px","background":"#8FD5E7","width":"auto","lineHeight":"30px","fontSize":"14px","height":"30px"}' @click="back()">返回</el-button>
      </el-form-item>
    </el-form>
</div>
</template>

<script>
  export default {
    data() {
	  let self = this
      return {
        id: '',
        baseUrl: '',
        ro:{
				xianlumingcheng : false,
				xianlutupian : false,
				jingdianmingcheng : false,
				jingdianleixing : false,
				jingdianweizhi : false,
				qidian : false,
				tujingluduan : false,
				zhongdian : false,
				xianlufeiyong : false,
				baotuanminge : false,
				chufariqi : false,
				jiaotongfangshi : false,
				xianluxiangqing : false,
				daoyougonghao : false,
				daoyouxingming : false,
				lianxifangshi : false,
				gerenlvli : false,
				thumbsupnum : false,
				crazilynum : false,
				discussnum : false,
				storeupnum : false,
        },
        type: '',
        userTableName: localStorage.getItem('UserTableName'),
        ruleForm: {
          xianlumingcheng: '',
          xianlutupian: '',
          jingdianmingcheng: '',
          jingdianleixing: '',
          jingdianweizhi: '',
          qidian: '',
          tujingluduan: '',
          zhongdian: '',
          xianlufeiyong: '',
          baotuanminge: '',
          chufariqi: '',
          jiaotongfangshi: '',
          xianluxiangqing: '',
          daoyougonghao: '',
          daoyouxingming: '',
          lianxifangshi: '',
          gerenlvli: '',
          thumbsupnum: '',
          crazilynum: '',
          discussnum: '',
          storeupnum: '',
        },
        jingdianmingchengOptions: [],

            chufariqiPickerOptions: {
                disabledDate(time) {
                    return time.getTime() < Date.now() - 8.64e7;
                }
            },

        rules: {
          xianlumingcheng: [
            { required: true, message: '线路名称不能为空', trigger: 'blur' },
          ],
          xianlutupian: [
          ],
          jingdianmingcheng: [
            { required: true, message: '景点名称不能为空', trigger: 'blur' },
          ],
          jingdianleixing: [
          ],
          jingdianweizhi: [
            { required: true, message: '景点位置不能为空', trigger: 'blur' },
          ],
          qidian: [
          ],
          tujingluduan: [
          ],
          zhongdian: [
          ],
          xianlufeiyong: [
            { required: true, message: '线路费用不能为空', trigger: 'blur' },
            { validator: this.$validate.isNumber, trigger: 'blur' },
          ],
          baotuanminge: [
            { validator: this.$validate.isIntNumer, trigger: 'blur' },
          ],
          chufariqi: [
          ],
          jiaotongfangshi: [
          ],
          xianluxiangqing: [
          ],
          daoyougonghao: [
          ],
          daoyouxingming: [
          ],
          lianxifangshi: [
            { validator: this.$validate.isMobile, trigger: 'blur' },
          ],
          gerenlvli: [
          ],
          thumbsupnum: [
            { validator: this.$validate.isIntNumer, trigger: 'blur' },
          ],
          crazilynum: [
            { validator: this.$validate.isIntNumer, trigger: 'blur' },
          ],
          discussnum: [
            { validator: this.$validate.isIntNumer, trigger: 'blur' },
          ],
          storeupnum: [
            { validator: this.$validate.isIntNumer, trigger: 'blur' },
          ],
        },
		centerType: false,
      };
    },
    computed: {



    },
    components: {
    },
    created() {
		if(this.$route.query.centerType){
			this.centerType = true
		}
	  //this.bg();
      let type = this.$route.query.type ? this.$route.query.type : '';
      this.init(type);
      this.baseUrl = this.$config.baseUrl;
    },
    methods: {
      getMakeZero(s) {
          return s < 10 ? '0' + s : s;
      },
      // 下载
      download(file){
        window.open(`${file}`)
      },
      // 初始化
      init(type) {
        this.type = type;
        if(type=='cross'){
          var obj = JSON.parse(localStorage.getItem('crossObj'));
          for (var o in obj){
            if(o=='xianlumingcheng'){
              this.ruleForm.xianlumingcheng = obj[o];
              this.ro.xianlumingcheng = true;
              continue;
            }
            if(o=='xianlutupian'){
              this.ruleForm.xianlutupian = obj[o].split(",")[0];
              this.ro.xianlutupian = true;
              continue;
            }
            if(o=='jingdianmingcheng'){
              this.ruleForm.jingdianmingcheng = obj[o];
              this.ro.jingdianmingcheng = true;
              continue;
            }
            if(o=='jingdianleixing'){
              this.ruleForm.jingdianleixing = obj[o];
              this.ro.jingdianleixing = true;
              continue;
            }
            if(o=='jingdianweizhi'){
              this.ruleForm.jingdianweizhi = obj[o];
              this.ro.jingdianweizhi = true;
              continue;
            }
            if(o=='qidian'){
              this.ruleForm.qidian = obj[o];
              this.ro.qidian = true;
              continue;
            }
            if(o=='tujingluduan'){
              this.ruleForm.tujingluduan = obj[o];
              this.ro.tujingluduan = true;
              continue;
            }
            if(o=='zhongdian'){
              this.ruleForm.zhongdian = obj[o];
              this.ro.zhongdian = true;
              continue;
            }
            if(o=='xianlufeiyong'){
              this.ruleForm.xianlufeiyong = obj[o];
              this.ro.xianlufeiyong = true;
              continue;
            }
            if(o=='baotuanminge'){
              this.ruleForm.baotuanminge = obj[o];
              this.ro.baotuanminge = true;
              continue;
            }
            if(o=='chufariqi'){
              this.ruleForm.chufariqi = obj[o];
              this.ro.chufariqi = true;
              continue;
            }
            if(o=='jiaotongfangshi'){
              this.ruleForm.jiaotongfangshi = obj[o];
              this.ro.jiaotongfangshi = true;
              continue;
            }
            if(o=='xianluxiangqing'){
              this.ruleForm.xianluxiangqing = obj[o];
              this.ro.xianluxiangqing = true;
              continue;
            }
            if(o=='daoyougonghao'){
              this.ruleForm.daoyougonghao = obj[o];
              this.ro.daoyougonghao = true;
              continue;
            }
            if(o=='daoyouxingming'){
              this.ruleForm.daoyouxingming = obj[o];
              this.ro.daoyouxingming = true;
              continue;
            }
            if(o=='lianxifangshi'){
              this.ruleForm.lianxifangshi = obj[o];
              this.ro.lianxifangshi = true;
              continue;
            }
            if(o=='gerenlvli'){
              this.ruleForm.gerenlvli = obj[o];
              this.ro.gerenlvli = true;
              continue;
            }
            if(o=='thumbsupnum'){
              this.ruleForm.thumbsupnum = obj[o];
              this.ro.thumbsupnum = true;
              continue;
            }
            if(o=='crazilynum'){
              this.ruleForm.crazilynum = obj[o];
              this.ro.crazilynum = true;
              continue;
            }
            if(o=='discussnum'){
              this.ruleForm.discussnum = obj[o];
              this.ro.discussnum = true;
              continue;
            }
            if(o=='storeupnum'){
              this.ruleForm.storeupnum = obj[o];
              this.ro.storeupnum = true;
              continue;
            }
          }
        }else if(type=='edit'){
			this.info()
		}
        // 获取用户信息
        this.$http.get(this.userTableName + '/session', {emulateJSON: true}).then(res => {
          if (res.data.code == 0) {
            var json = res.data.data;
            if((json.daoyougonghao!=''&&json.daoyougonghao) || json.daoyougonghao==0){
                this.ruleForm.daoyougonghao = json.daoyougonghao
            }
            if((json.daoyouxingming!=''&&json.daoyouxingming) || json.daoyouxingming==0){
                this.ruleForm.daoyouxingming = json.daoyouxingming
            }
            if((json.lianxifangshi!=''&&json.lianxifangshi) || json.lianxifangshi==0){
                this.ruleForm.lianxifangshi = json.lianxifangshi
            }
            if((json.gerenlvli!=''&&json.gerenlvli) || json.gerenlvli==0){
                this.ruleForm.gerenlvli = json.gerenlvli
            }
          }
        });
        this.$http.get('option/remenjingdian/jingdianmingcheng', {emulateJSON: true}).then(res => {
          if (res.data.code == 0) {
            this.jingdianmingchengOptions = res.data.data;
          }
        });

		if (localStorage.getItem('raffleType') && localStorage.getItem('raffleType') != null) {
			localStorage.removeItem('raffleType')
			setTimeout(() => {
				this.onSubmit()
			}, 300)
		}
      },
      // 下二随
      jingdianmingchengChange () {
        this.$http.get('follow/remenjingdian/jingdianmingcheng?columnValue=' + this.ruleForm.jingdianmingcheng, {emulateJSON: true}).then(res => {
          if (res.data.code == 0) {
            if(res.data.data.jingdianleixing){
              this.ruleForm.jingdianleixing = res.data.data.jingdianleixing
            }
            if(res.data.data.jingdianweizhi){
              this.ruleForm.jingdianweizhi = res.data.data.jingdianweizhi
            }
          }
        });
      },

    // 多级联动参数
      // 多级联动参数
      info() {
        this.$http.get(`lvyouxianlu/detail/${this.$route.query.id}`, {emulateJSON: true}).then(res => {
          if (res.data.code == 0) {
            this.ruleForm = res.data.data;
          }
        });
      },
      // 提交
      onSubmit() {

			//更新跨表属性
			var crossuserid;
			var crossrefid;
			var crossoptnum;
			this.$refs["ruleForm"].validate(valid => {
				if(valid) {
					if(this.type=='cross'){
						var statusColumnName = localStorage.getItem('statusColumnName');
						var statusColumnValue = localStorage.getItem('statusColumnValue');
						if(statusColumnName && statusColumnName!='') {
							var obj = JSON.parse(localStorage.getItem('crossObj'));
							if(!statusColumnName.startsWith("[")) {
								for (var o in obj){
									if(o==statusColumnName){
										obj[o] = statusColumnValue;
									}
								}
								var table = localStorage.getItem('crossTable');
								this.$http.post(table+'/update', obj).then(res => {});
							} else {
								crossuserid=Number(localStorage.getItem('frontUserid'));
								crossrefid=obj['id'];
								crossoptnum=localStorage.getItem('statusColumnName');
								crossoptnum=crossoptnum.replace(/\[/,"").replace(/\]/,"");
							}
						}
					}
					if(crossrefid && crossuserid) {
						this.ruleForm.crossuserid=crossuserid;
						this.ruleForm.crossrefid=crossrefid;
						var params = {
							page: 1,
							limit: 10,
							crossuserid:crossuserid,
							crossrefid:crossrefid,
						}
						this.$http.get('lvyouxianlu/list', {
							params: params
						}).then(res => {
							if(res.data.data.total>=crossoptnum) {
								this.$message({
									message: localStorage.getItem('tips'),
									type: 'error',
									duration: 1500,
								});
								return false;
							} else {
								// 跨表计算


								this.$http.post(`lvyouxianlu/${this.ruleForm.id?'update':this.centerType?'save':'add'}`, this.ruleForm).then(res => {
									if (res.data.code == 0) {
										this.$message({
											message: '操作成功',
											type: 'success',
											duration: 1500,
											onClose: () => {
												this.$router.go(-1);
											}
										});
									} else {
										this.$message({
											message: res.data.msg,
											type: 'error',
											duration: 1500
										});
									}
								});
							}
						});
					} else {


						this.$http.post(`lvyouxianlu/${this.ruleForm.id?'update':this.centerType?'save':'add'}`, this.ruleForm).then(res => {
							if (res.data.code == 0) {
								this.$message({
									message: '操作成功',
									type: 'success',
									duration: 1500,
									onClose: () => {
										this.$router.go(-1);
									}
								});
							} else {
								this.$message({
									message: res.data.msg,
									type: 'error',
									duration: 1500
								});
							}
						});
					}
				}
			});
		},
		// 获取uuid
		getUUID () {
			return new Date().getTime();
		},
		// 返回
		back() {
			this.$router.go(-1);
		},
      xianlutupianUploadChange(fileUrls) {
          this.ruleForm.xianlutupian = fileUrls.replace(new RegExp(this.$config.baseUrl,"g"),"");;
      },
    }
  };
</script>

